import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable, forkJoin, map } from 'rxjs';
import { environment } from '../../../environments/environment';
import { Student } from './student.service';

export interface BulletinData {
  student: Student;
  grades: any[];
  term: string;
  classAverage: number;
  scientificAverage: number;
  literaryAverage: number;
  sportsAverage: number;
  classRank: number;
  schoolRank: number;
  totalStudents: number;
  teachers: { [subject: string]: string };
}

@Injectable({ providedIn: 'root' })
export class BulletinService {
  private apiUrl = environment.apiUrl;

  constructor(private http: HttpClient) {}

  getBulletinData(studentId: number, term: string): Observable<BulletinData> {
    return forkJoin({
      student: this.http.get<Student>(`${this.apiUrl}/students/${studentId}`),
      grades: this.http.get<any[]>(`${this.apiUrl}/grades/student/${studentId}`),
      allStudents: this.http.get<Student[]>(`${this.apiUrl}/students`),
      allGrades: this.http.get<any[]>(`${this.apiUrl}/grades`)
    }).pipe(
      map(({ student, grades, allStudents, allGrades }) => {
        const filteredGrades = term ? grades.filter(g => g.term === term) : grades;

        // Calcul des moyennes
        const classAverage = filteredGrades.length > 0
          ? filteredGrades.reduce((sum, g) => sum + g.score, 0) / filteredGrades.length
          : 0;

        // Moyennes par catégorie
        const scientificSubjects = ['Mathématiques', 'Physique-Chimie', 'Sciences de la vie et de la Terre (SVT)', 'Sciences de l\'ingénieur', 'Informatique'];
        const literarySubjects = ['Français', 'Philosophie', 'Histoire-Géographie', 'Anglais', 'Espagnol', 'Allemand', 'Latin', 'Grec'];
        const sportsSubjects = ['Éducation physique et sportive (EPS)', 'Éducation physique et sportive'];

        const scientificGrades = filteredGrades.filter(g => scientificSubjects.includes(g.subject));
        const literaryGrades = filteredGrades.filter(g => literarySubjects.includes(g.subject));
        const sportsGrades = filteredGrades.filter(g => sportsSubjects.includes(g.subject));

        const scientificAverage = scientificGrades.length > 0
          ? scientificGrades.reduce((sum, g) => sum + g.score, 0) / scientificGrades.length
          : 0;

        const literaryAverage = literaryGrades.length > 0
          ? literaryGrades.reduce((sum, g) => sum + g.score, 0) / literaryGrades.length
          : 0;

        const sportsAverage = sportsGrades.length > 0
          ? sportsGrades.reduce((sum, g) => sum + g.score, 0) / sportsGrades.length
          : 0;

        // Calcul des rangs (simplifié)
        const studentAverages = allStudents.map(s => {
          const studentGrades = allGrades.filter(g => g.studentId === s.id);
          const filtered = term ? studentGrades.filter(g => g.term === term) : studentGrades;
          const avg = filtered.length > 0 ? filtered.reduce((sum, g) => sum + g.score, 0) / filtered.length : 0;
          return { id: s.id, average: avg };
        }).sort((a, b) => b.average - a.average);

        const classRank = studentAverages.findIndex(s => s.id === studentId) + 1;
        const schoolRank = classRank; // Simplifié, devrait être calculé par classe

        // Noms des professeurs (simplifié)
        const teachers: { [subject: string]: string } = {};
        filteredGrades.forEach(g => {
          if (g.teacher) {
            teachers[g.subject] = `${g.teacher.firstName} ${g.teacher.lastName}`;
          }
        });

        return {
          student,
          grades: filteredGrades,
          term,
          classAverage,
          scientificAverage,
          literaryAverage,
          sportsAverage,
          classRank,
          schoolRank,
          totalStudents: allStudents.length,
          teachers
        };
      })
    );
  }

  generateAllBulletins(term: string): Observable<BulletinData[]> {
    return this.http.get<Student[]>(`${this.apiUrl}/students`).pipe(
      map(students => {
        // Retourne un tableau vide pour l'instant, sera implémenté avec un appel réel
        return [];
      })
    );
  }
}
